import subprocess
import sys
import json

DOMAIN = '{domain}'
DC_IP = '{dc_ip}'
USERNAME = '{username}'
PASSWORD = '{password}'

def ldap_query(base_dn, ldap_filter, attributes):
    cmd = ['ldapsearch', '-x', '-H', f'ldap://{DC_IP}', '-D', f'{USERNAME}@{DOMAIN}', '-w', PASSWORD, '-b', base_dn, ldap_filter] + attributes
    try:
        result = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
        return result.stdout
    except: return ''

def enum_users(base_dn):
    output = ldap_query(base_dn, '(&(objectClass=user)(objectCategory=person))', ['sAMAccountName', 'memberOf', 'adminCount', 'lastLogon'])
    users = []
    current = {}
    for line in output.split('\n'):
        if line.startswith('sAMAccountName:'): current['name'] = line.split(':',1)[1].strip()
        elif line.startswith('adminCount:'): current['admin'] = line.split(':',1)[1].strip()
        elif line.startswith('dn:'):
            if current: users.append(current)
            current = {}
    if current: users.append(current)
    return users

def enum_spn(base_dn):
    output = ldap_query(base_dn, '(&(objectClass=user)(servicePrincipalName=*))', ['sAMAccountName', 'servicePrincipalName'])
    spns = []
    for line in output.split('\n'):
        if 'servicePrincipalName:' in line:
            spns.append(line.split(':',1)[1].strip())
    return spns

print(f'=== AD Enumerator ===')
print(f'Domain: {DOMAIN}, DC: {DC_IP}')

parts = DOMAIN.split('.')
base_dn = ','.join(f'DC={p}' for p in parts)

users = enum_users(base_dn)
print(f'\nUsers: {len(users)}')
admins = [u for u in users if u.get('admin') == '1']
print(f'Admin accounts: {len(admins)}')
for u in admins: print(f'  [!] {u["name"]}')

spns = enum_spn(base_dn)
print(f'\nSPNs (Kerberoastable): {len(spns)}')
for s in spns[:10]: print(f'  {s}')

